/**
 * Aptitude Seed Script — Number System (ESM, no TypeScript)
 * Run: node scripts/seed-aptitude.mjs
 */

import mongoose from 'mongoose'
import { readFileSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))

// Load env
const envPath = join(__dirname, '..', '.env.local')
const envContent = readFileSync(envPath, 'utf-8')
const envVars = {}
for (const line of envContent.split('\n')) {
  const eqIdx = line.indexOf('=')
  if (eqIdx === -1) continue
  const k = line.slice(0, eqIdx).trim()
  let v = line.slice(eqIdx + 1).trim()
  // Strip surrounding quotes
  if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
    v = v.slice(1, -1)
  }
  if (k) envVars[k] = v
}
const MONGODB_URI = envVars['MONGODB_URI']
if (!MONGODB_URI) { console.error('MONGODB_URI not found in .env.local'); process.exit(1) }

// ─── Schemas ──────────────────────────────────────────────────────────────────
const { Schema, model, connect, connection } = mongoose

const ConceptSchema = new Schema({ conceptId:String, name:String, slug:String, description:String, totalQuestions:Number, totalFormulas:Number, totalModels:Number, models:[String], cheatsheet:{formulas:[String],tips:[String],tricks:[String]} }, { timestamps:true, collection:'aptitude_concepts' })
const FormulaSchema = new Schema({ formulaId:String, conceptSlug:String, title:String, expression:String, plainText:String, explanation:String, derivation:String, questionCount:Number, questionIds:[String], tags:[String], source:String }, { timestamps:true, collection:'aptitude_formulas' })
const ModelSchema  = new Schema({ modelId:String, conceptSlug:String, name:String, description:String, questionIds:[String], formulaIds:[String], questionCount:Number, difficulty:String }, { timestamps:true, collection:'aptitude_models' })
const StepSchema   = new Schema({ stepNumber:Number, explanation:String, formula:String, formulaExpression:String, calculation:String, result:String }, { _id:false })
const SolSchema    = new Schema({ steps:[StepSchema], shortcut:String, commonMistake:String, timeToSolve:String }, { _id:false })
const QuestionSchema = new Schema({ questionId:String, conceptSlug:String, modelId:String, formulaIds:[String], questionText:String, questionType:String, options:[String], correctAnswer:String, difficulty:String, solution:SolSchema, source:String, sourcePage:String, sourceType:String, tags:[String] }, { timestamps:true, collection:'aptitude_questions' })
const MetaSchema   = new Schema({ _id:String, lastQuestionNumber:Number, lastFormulaNumber:Number, lastModelNumber:Number, lastConceptNumber:Number }, { timestamps:true, collection:'aptitude_meta' })

const Concept  = model('AptConceptS',  ConceptSchema)
const Formula  = model('AptFormulaS',  FormulaSchema)
const AModel   = model('AptModelS',    ModelSchema)
const Question = model('AptQuestionS', QuestionSchema)
const Meta     = model('AptMetaS',     MetaSchema)

