// ─── Tips & Tricks ────────────────────────────────────────────────────────────

const TIPS = [
  'Face value is always the digit itself; place value = digit × positional power of 10.',
  'For divisibility by 9: digit sum must be divisible by 9. Same rule for 3.',
  'Divisibility by 11: (odd-position sum) − (even-position sum) = 0 or ±11.',
  '2 is the only even prime. 1 is neither prime nor composite.',
  'All primes > 3 are of the form 6k ± 1.',
  'For squaring near multiples of 10: use (a+b)² or (a-b)².',
  'Product of any n consecutive integers is divisible by n!',
  'Any 6-digit number abcabc = abc × 1001 = abc × 7 × 11 × 13.',
  '(xⁿ-aⁿ) is always divisible by (x-a) for all natural n.',
  'Trailing zeros in a product = min(power of 2, power of 5).',
]

const TRICKS = [
  'N × 999 = N × 1000 − N: instant multiply by 999.',
  '5ⁿ = 10ⁿ / 2ⁿ: multiply by 10ⁿ then halve n times.',
  'For squaring: split as (round number ± small)² using (a±b)².',
  'Unit digit cycles: 0,1,5,6→always same; 4,9→cycle 2; 2,3,7,8→cycle 4.',
  'Trailing zeros in n! = ⌊n/5⌋ + ⌊n/25⌋ + ⌊n/125⌋ + …',
  'a²−b² = (a+b)(a−b): much faster than computing squares.',
  'To check if same remainder: test if divisor divides difference of the two numbers.',
  'Remainder rules: if N=Dk+R, then N mod (D/m) = R mod (D/m).',
  'Sum of first n odd numbers = n². Sum of first n even numbers = n(n+1).',
  'abcabc = abc × 1001 — always divisible by 7, 11, 13.',
]

// ─── Main ─────────────────────────────────────────────────────────────────────

async function main() {
  console.log('🌱 Connecting to MongoDB...')
  await connect(MONGODB_URI, { dbName: 'swaseekh' })
  console.log('✅ Connected\n')

  // Drop existing
  const db = connection.db
  console.log('🗑️  Clearing aptitude collections...')
  await Promise.all([
    db.collection('aptitude_meta').deleteMany({}),
    db.collection('aptitude_concepts').deleteMany({}),
    db.collection('aptitude_formulas').deleteMany({}),
    db.collection('aptitude_models').deleteMany({}),
    db.collection('aptitude_questions').deleteMany({}),
  ])
  console.log('✅ Cleared\n')

  // Formulas
  console.log(`📐 Inserting ${FORMULAS.length} formulas...`)
  await Formula.insertMany(FORMULAS.map(f => ({ ...f, questionCount:0, questionIds:[] })))
  console.log('✅ Done\n')

  // Models
  console.log(`🗂  Inserting ${MODELS_DATA.length} models...`)
  await AModel.insertMany(MODELS_DATA.map(m => ({ ...m, questionIds:[], questionCount:0 })))
  console.log('✅ Done\n')

  // Questions — deduplicate
  const seen = new Set()
  const deduped = QUESTIONS.filter(q => {
    if (seen.has(q.questionId)) return false
    seen.add(q.questionId)
    return true
  })
  console.log(`❓ Inserting ${deduped.length} questions...`)
  for (let i = 0; i < deduped.length; i += 50) {
    await Question.insertMany(deduped.slice(i, i+50))
    process.stdout.write(`   ${Math.min(i+50, deduped.length)}/${deduped.length}\r`)
  }
  console.log('\n✅ Done\n')

  // Update model counts
  console.log('🔗 Updating model question counts...')
  for (const m of MODELS_DATA) {
    const ids = deduped.filter(q => q.modelId === m.modelId).map(q => q.questionId)
    await AModel.updateOne({ modelId: m.modelId }, { $set: { questionCount: ids.length, questionIds: ids } })
  }

  // Update formula counts
  console.log('🔗 Updating formula question counts...')
  for (const f of FORMULAS) {
    const ids = deduped.filter(q => q.formulaIds.includes(f.formulaId)).map(q => q.questionId)
    await Formula.updateOne({ formulaId: f.formulaId }, { $set: { questionCount: ids.length, questionIds: ids } })
  }

  // Insert concept
  console.log('📚 Inserting concept...')
  await Concept.create({
    conceptId: 'APT-CON-001',
    name: 'Number System',
    slug: 'number-system',
    description: 'Complete Number System coverage: place values, divisibility rules, prime numbers, remainders, unit digits, trailing zeros, algebraic identities, and series sums. Includes RS Agarwal solved examples, 380 exercise questions, and IndiaBix practice problems.',
    totalQuestions: deduped.length,
    totalFormulas: FORMULAS.length,
    totalModels: MODELS_DATA.length,
    models: MODELS_DATA.map(m => m.modelId),
    cheatsheet: {
      formulas: FORMULAS.map(f => f.formulaId),
      tips: TIPS,
      tricks: TRICKS,
    },
  })

  // Meta counters
  const maxQ = Math.max(...deduped.map(q => parseInt(q.questionId.replace('APT-Q-',''))))
  await Meta.findOneAndUpdate(
    { _id: 'counters' },
    { $set: { lastQuestionNumber: maxQ, lastFormulaNumber: FORMULAS.length, lastModelNumber: MODELS_DATA.length, lastConceptNumber: 1 } },
    { upsert: true }
  )

  console.log('\n🎉 Seeding complete!')
  console.log(`   Questions: ${deduped.length}`)
  console.log(`   Formulas:  ${FORMULAS.length}`)
  console.log(`   Models:    ${MODELS_DATA.length}`)

  await connection.close()
  process.exit(0)
}

main().catch(err => { console.error('❌', err); process.exit(1) })
